import React, { useEffect, useState } from 'react';
import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { getUnreadCount } from '../services/notificationApi';

const HomeHeader = () => {
  const navigation = useNavigation();
  const [unreadCount, setUnreadCount] = useState(0);

  const fetchCount = async () => {
    try {
      const count = await getUnreadCount();
      setUnreadCount(count);
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    fetchCount();
    const interval = setInterval(fetchCount, 30000); // 30 secondes
    return () => clearInterval(interval);
  }, []);

  return (
    <View style={styles.header}>
      <Text style={styles.logo}>ShopElectro</Text>
      <View style={styles.icons}>
        <TouchableOpacity onPress={() => navigation.navigate('Search')}>
          <Text style={styles.icon}>🔍</Text>
        </TouchableOpacity>
        <TouchableOpacity onPress={() => navigation.navigate('NotificationList')}>
          <View style={styles.notifContainer}>
            <Text style={styles.icon}>🔔</Text>
            {unreadCount > 0 && (
              <View style={styles.badge}>
                <Text style={styles.badgeText}>{unreadCount > 99 ? '99+' : unreadCount}</Text>
              </View>
            )}
          </View>
        </TouchableOpacity>
      </View>
    </View>
  );
};

const styles = StyleSheet.create({
  header: { flexDirection: 'row', justifyContent: 'space-between', padding: 16, backgroundColor: '#fff', alignItems: 'center' },
  logo: { fontSize: 20, fontWeight: 'bold' },
  icons: { flexDirection: 'row', gap: 20 },
  icon: { fontSize: 24 },
  notifContainer: { position: 'relative' },
  badge: { position: 'absolute', top: -6, right: -10, backgroundColor: 'red', borderRadius: 12, minWidth: 18, paddingHorizontal: 4, alignItems: 'center' },
  badgeText: { color: 'white', fontSize: 10, fontWeight: 'bold' }
});

export default HomeHeader;
```

