import React from 'react';
import { FlatList, View, Text, Image, TouchableOpacity, Dimensions, StyleSheet } from 'react-native';

const { width } = Dimensions.get('window');
const ITEM_WIDTH = width - 40;

const PromoCarousel = ({ data, onPressItem }) => {
  const renderItem = ({ item }) => (
    <TouchableOpacity 
      style={[styles.item, { width: ITEM_WIDTH }]} 
      onPress={() => onPressItem(item.link)}
    >
      <Image source={{ uri: item.imageUrl }} style={styles.image} />
      <View style={styles.overlay}>
        <Text style={styles.title}>{item.title}</Text>
      </View>
    </TouchableOpacity>
  );

  return (
    <FlatList
      data={data}
      horizontal
      pagingEnabled
      showsHorizontalScrollIndicator={false}
      renderItem={renderItem}
      keyExtractor={item => item.id}
      snapToInterval={ITEM_WIDTH + 20}
      decelerationRate="fast"
      contentContainerStyle={{ paddingHorizontal: 20 }}
      ItemSeparatorComponent={() => <View style={{ width: 12 }} />}
    />
  );
};

const styles = StyleSheet.create({
  item: { borderRadius: 16, overflow: 'hidden', height: 150 },
  image: { width: '100%', height: '100%', resizeMode: 'cover' },
  overlay: { position: 'absolute', bottom: 0, left: 0, right: 0, backgroundColor: 'rgba(0,0,0,0.5)', padding: 8 },
  title: { color: 'white', fontWeight: 'bold' }
});
```

On utilise FlatList avec `numColumns={2}` et `columnWrapperStyle` pour espacer les colonnes. Chaque item a une largeur calculée : `(largeur écran - espacements) / 2`. On utilise `contentContainerStyle` pour le padding. Exemple: 
```jsx
<FlatList
  data={categories}
  numColumns={2}
  columnWrapperStyle={{ justifyContent: 'space-between', marginBottom: 16 }}
  renderItem={({item}) => <CategoryCard category={item} />}
/>
```
Dans CategoryCard, on applique `width: '47%'` ou une largeur fixe calculée dynamiquement.

